mapper.select:
SELECT SUM(TRANS_PERF_CNT) AS TRANS_PERF_CNT, SUM(TRANS_ALARM_CNT) AS TRANS_ALARM_CNT, SUM(IP_RESOURCE_CNT) AS IP_RESOURCE_CNT, SUM(IP_ALARM_CNT) AS IP_ALARM_CNT, SUM(IP_PERF_CNT) AS IP_PERF_CNT, SUM(IP_SFLOW_CNT) AS IP_SFLOW_CNT,s SUM(TICKET_RT_CNT) AS TICKET_RT_CNT, SUM(TICKET_ATT_CNT) AS TICKET_ATT_CNT, SUM(TICKET_NTT_CNT) AS TICKET_NTT_CNT, SUM(TICKET_PF_CNT) AS TICKET_PF_CNT, SUM(LINK_TOTAL_RESOURCE_CNT) AS LINK_TOTAL_RESOURCE_CNT, SUM(LINK_TOTAL_ALARM_CNT) AS LINK_TOTAL_ALARM_CNT, SUM(LINK_IP_PERF_CNT) AS LINK_IP_PERF_CNT, SUM(LINK_TRANS_PERF_CNT) AS LINK_TRANS_PERF_CNT FROM nia.tb_opsts WHERE 1=1
AND OPSTS_TIME = #{SEARCH_DATE}
AND OPSTS_GB = #{DATE_TYPE}

SELECT CASE WHEN tpd.SELF_PROCESS_TYPE = 'S' THEN tpd.ALARMNO ELSE tpd.TICKET_ID END AS TICKET_ID , TO_CHAR(OCCUR_TIME, 'YYYY-MM-DD HH24:MI:SS') AS OCCUR_TIME , TO_CHAR(CLOS_TIME, 'YYYY-MM-DD HH24:MI:SS') AS CLOS_TIME , tpd.TICKET_TYPE , SELF_PROCESS_TYPE , CASE WHEN tpd.SELF_PROCESS_TYPE = 'S' THEN tss.FAULT_DETAIL_CONTENT ELSE ts.FAULT_DETAIL_CONTENT END AS FAULT_DETAIL_CONTENT , CLOS_TYPE , CLOS_STATUS FROM nia.tb_auto_treat_process_dtl tpd LEFT JOIN nia.tb_sop ts ON tpd.ticket_id = ts.ticket_id LEFT JOIN nia.tb_syslog_sop tss ON tpd.alarmno = tss.alarmno WHERE 1=1
AND DATE_TRUNC('MONTH', tpd.OCCUR_TIME) = TO_TIMESTAMP(CONCAT(#{DATE_TIME}, '-01'), 'YYYY-MM-DD')
AND tpd.OCCUR_TIME >= #{DATE_TIME}::TIMESTAMP AND tpd.OCCUR_TIME < #{DATE_TIME}::TIMESTAMP + ('1'||#{DATE_TYPE})::INTERVAL
AND tpd.SELF_PROCESS_GROUP = #{SELF_PROCESS_GROUP}
AND tpd.SELF_PROCESS_TYPE = #{SELF_PROCESS_TYPE}
AND tpd.CLOS_TYPE = #{CLOS_TYPE}
AND tpd.CLOS_STATUS = #{CLOS_STATUS}
ORDER BY TPD.OCCUR_TIME DESC

SELECT src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name, dst_country_code, packet_bytes, row_number FROM ( SELECT src_ip, src_nren_id, src_nren_name , src_country_code, dst_ip, dst_nren_id, dst_nren_name , dst_country_code , SUM(packet_bytes) packet_bytes , row_number() over (ORDER BY case when src_nren_id is null and dst_nren_id is null then 0 else 2 end desc, SUM(packet_bytes) DESC) row_number FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 AND dt.collect_timestamp <= CURRENT_DATE AND dt.collect_timestamp >= CURRENT_DATE - interval '5 days'
AND src_nren_id = #{src_nren_name}
AND src_ip LIKE '%' || #{src_ip} || '%'
AND dst_nren_id = #{dst_nren_name}
AND dst_ip LIKE '%' || #{dst_ip} || '%'
GROUP BY src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name , dst_country_code ) dt LIMIT 100

SELECT src_protocol, src_port, dst_protocol, dst_port, ROUND(packet_bytes / (1024 * 1024), 2) AS packet_bytes, rank_order FROM ( SELECT src_protocol, src_port, dst_protocol, dst_port, SUM(packet_bytes) packet_bytes , row_number() over (ORDER BY CASE WHEN src_protocol IS NULL AND dst_protocol IS NULL THEN 0 ELSE 2 END DESC, SUM(packet_bytes) DESC) rank_order FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 AND dt.collect_timestamp <= CURRENT_DATE AND dt.collect_timestamp >= CURRENT_DATE - interval '5 days'
AND src_port = #{src_protocol}
AND src_port like '%' || #{src_port} || '%'
AND dst_port = #{dst_protocol}
AND dst_port like '%' || #{dst_port} || '%'
GROUP BY src_protocol, src_port, dst_protocol, dst_port ) dt limit 200
